/**
 * MoleculeRegistry.ts
 * ~300 key molecules with real thermodynamic data.
 * ΔHf and ΔGf values from NIST WebBook / JANAF tables (kJ/mol at 298.15 K, 1 atm).
 * Cp values from NIST / CRC Handbook (J/mol·K at 25°C).
 * Densities are liquid-phase unless noted.
 */

export interface Molecule {
  id:          number
  formula:     string
  name:        string
  molarMass:   number         // g/mol
  meltingC:    number | null  // °C
  boilingC:    number | null  // °C
  densityGcm3: number | null  // g/cm³ (liquid at STP unless noted)
  deltaHf:     number         // standard enthalpy of formation kJ/mol
  deltaGf:     number         // standard Gibbs free energy of formation kJ/mol
  Cp:          number         // molar heat capacity J/mol·K
  phaseAtSTP:  'solid' | 'liquid' | 'gas' | 'plasma'
  bioRole:     string | null
  colorHex:    string
  elements:    Record<string, number>  // { symbol: count }
}

