// ── Lookup helpers ────────────────────────────────────────────────────────────

const _byId      = new Map<number, Molecule>(MOLECULES.map(m => [m.id, m]))
const _byFormula = new Map<string, Molecule>()
MOLECULES.forEach(m => {
  if (!_byFormula.has(m.formula)) _byFormula.set(m.formula, m)
})

export function getMoleculeById(id: number): Molecule | undefined {
  return _byId.get(id)
}

export function getMoleculeByFormula(f: string): Molecule | undefined {
  return _byFormula.get(f)
}
